def esc(v):
    return html.escape(str(v), quote=True)

def art(motif, name):
    paths={
      'plate':'<circle cx="200" cy="190" r="115"/><circle cx="200" cy="190" r="55"/><path d="M85 320h230"/>',
      'glass':'<path d="M120 70h160l-25 115c-8 38-35 60-55 60s-47-22-55-60zM200 245v70M145 315h110"/>',
      'spice':'<circle cx="200" cy="190" r="110"/><path d="M120 220c45-95 115-95 160 0M145 145l110 90M255 145l-110 90"/>',
      'sushi':'<ellipse cx="200" cy="190" rx="120" ry="70"/><ellipse cx="200" cy="190" rx="55" ry="30"/><path d="M100 285h200"/>',
      'croissant':'<path d="M85 215c35-95 195-95 230 0-35 45-70 60-115 60s-80-15-115-60zM140 165c5 50 5 85 0 105M200 145v125M260 165c-5 50-5 85 0 105"/>',
      'screen':'<rect x="70" y="80" width="260" height="170" rx="18"/><path d="M155 315h90M200 250v65"/><circle cx="135" cy="165" r="22"/><circle cx="265" cy="165" r="22"/>',
      'market':'<path d="M75 140h250l-20 70H95zM110 210v110M290 210v110M130 270h140"/><path d="M95 140l30-60h150l30 60"/>',
      'chicken':'<path d="M105 210c20-85 170-105 205-15 25 65-35 120-115 110-75-8-110-42-90-95z"/><circle cx="275" cy="155" r="28"/><path d="M295 140l35-15-20 30"/>',
      'music':'<path d="M140 90v165c0 35-60 45-60 5 0-28 35-45 60-30M140 110l150-35v145c0 35-60 45-60 5 0-28 35-45 60-30"/>',
      'coffee':'<path d="M95 135h190v95c0 55-40 85-95 85s-95-30-95-85zM285 160h25c45 0 45 65 0 65h-25"/><path d="M145 90c-20-25 15-35 0-60M205 90c-20-25 15-35 0-60"/>',
      'crepe':'<path d="M80 280L200 80l120 200z"/><path d="M130 240h140M165 175h70"/>',
      'hibachi':'<path d="M70 250h260M100 250l25-120h150l25 120M135 300h130"/><path d="M165 115c-25-35 25-45 0-80M235 115c-25-35 25-45 0-80"/>',
      'pub':'<path d="M105 95h170v175c0 35-35 55-85 55s-85-20-85-55zM275 135h35c45 0 45 85 0 85h-35"/><path d="M145 135h85"/>',
      'courtyard':'<path d="M85 315V125l115-65 115 65v190M135 315v-85h130v85"/><circle cx="200" cy="160" r="28"/>',
      'house':'<path d="M70 175L200 65l130 110v145H70zM150 320v-100h100v100"/><circle cx="200" cy="160" r="24"/>'
    }
    body=paths.get(motif, paths['plate'])
    return f'<svg viewBox="0 0 400 400" role="img" aria-label="Custom illustration for {esc(name)}"><g fill="none" stroke="currentColor" stroke-width="11" stroke-linecap="round" stroke-linejoin="round">{body}</g><text x="200" y="385" text-anchor="middle" font-family="Arial" font-size="14" font-weight="700">{esc(name)}</text></svg>'

def nav(r,current):
    items=[('index.html','Home'),('menu.html','Menu'),('story.html','Story'),(r['tool'],r['toolName']),('visit.html','Visit')]
    links=[]
    for href,label in items:
        current_attr=' aria-current="page"' if href==current else ''
        links.append(f'<a href="{esc(href)}"{current_attr}>{esc(label)}</a>')
    return '<a class="skip" href="#main">Skip to content</a><div class="notice">Unofficial redesign concept • current details require owner confirmation • forms do not submit</div><nav class="site-nav"><a class="brand" href="index.html">'+esc(r['name'])+'</a><button class="nav-toggle" data-nav-toggle aria-expanded="false">Menu</button><div class="nav-links" data-nav-links>'+''.join(links)+'</div></nav>'

def shell(r,title,current,body,page_class=''):
    return f'<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="description" content="Unofficial five-page website concept for {esc(r["name"])}"><title>{esc(title)} | {esc(r["name"])}</title><link rel="stylesheet" href="site.css"></head><body class="layout-{esc(r["layout"])} {page_class}">{nav(r,current)}<main id="main">{body}</main><footer><strong>{esc(r["name"])}</strong><span>{esc(r["area"])}</span><p>Unofficial sales demonstration. Not affiliated with or operated by the restaurant.</p></footer><script src="site.js"></script></body></html>'

def home_page(r):
    previews=''.join(f'<article class="menu-preview"><small>{esc(cat)}</small><h3>{esc(items[0])}</h3><p>{esc(items[1])}</p></article>' for cat,items in r['menu'])
    facts=''.join(f'<article class="feature-card"><span>0{i}</span><h3>{esc(title)}</h3><p>{esc(text)}</p></article>' for i,(title,text) in enumerate(zip(['Discover','Understand','Plan'],r['facts']),1))
    if r['layout']=='editorial':
        body=f'<header class="hero editorial"><div class="hero-copy"><div class="eyebrow">{esc(r["area"])} • {esc(r["cuisine"])}</div><h1>{esc(r["name"])} deserves a site with the same sense of place as the dining room.</h1><p>This concept separates discovery, menu exploration and planning without inventing current operational details.</p><div class="actions"><a class="btn" href="menu.html">Explore the menu</a><a class="text-link" href="{esc(r["tool"])}">Open {esc(r["toolName"])}</a></div></div><div class="hero-art">{art(r["motif"],r["name"])}</div></header><section class="feature-grid">{facts}</section><section class="menu-preview-grid">{previews}</section>'
    elif r['layout']=='mosaic':
        body=f'<header class="hero mosaic"><div><div class="eyebrow">{esc(r["area"])} • {esc(r["cuisine"])}</div><h1>A more useful digital front door for {esc(r["name"])}.</h1><p>The experience leads with identity, then lets guests move quickly into menu categories and a restaurant-specific planning tool.</p><a class="btn" href="menu.html">Start with the menu</a></div><div class="hero-art">{art(r["motif"],r["name"])}</div><aside class="hero-note">Static QA complete • visual QA pending</aside></header><section class="menu-preview-grid mosaic-grid">{previews}</section><section class="feature-grid">{facts}</section>'
    elif r['layout']=='marquee':
        body=f'<header class="hero marquee"><div class="eyebrow">{esc(r["area"])} • {esc(r["cuisine"])}</div><h1>{esc(r["name"])} — clear choices, stronger atmosphere, easier planning.</h1><p>This five-page concept gives the restaurant a focused customer journey instead of a generic landing page.</p><div class="actions"><a class="btn" href="{esc(r["tool"])}">Use {esc(r["toolName"])}</a><a class="text-link" href="story.html">Read the story direction</a></div><div class="hero-art wide">{art(r["motif"],r["name"])}</div></header><section class="feature-grid">{facts}</section><section class="menu-preview-grid">{previews}</section>'
    else:
        body=f'<header class="hero split"><div><div class="eyebrow">{esc(r["area"])} • {esc(r["cuisine"])}</div><h1>Make the next visit to {esc(r["name"])} easier to imagine.</h1><p>The redesign clarifies menu paths, restaurant character and the next useful action.</p><div class="actions"><a class="btn" href="menu.html">Browse the menu</a><a class="text-link" href="visit.html">Plan a visit</a></div></div><div class="hero-art">{art(r["motif"],r["name"])}</div></header><section class="feature-grid">{facts}</section><section class="menu-preview-grid">{previews}</section>'
    return shell(r,'Home','index.html',body,'home')

def menu_page(r):
    cards=[]
    for cat,items in r['menu']:
        lis=''.join(f'<li data-menu-item>{esc(item)}<span>Concept item • confirm availability and price</span></li>' for item in items)
        cards.append(f'<section class="menu-group"><h2>{esc(cat)}</h2><ul>{lis}</ul></section>')
    body=f'<header class="page-head"><div class="eyebrow">Concept menu architecture</div><h1>Find the right route before the visit.</h1><p>These categories are directional and must be replaced with owner-approved menu content before launch.</p></header><section class="menu-search"><label>Search this concept menu<input type="search" placeholder="Search categories or dishes" data-menu-search></label><span data-menu-count></span></section><div class="menu-board">{"".join(cards)}</div>'
    return shell(r,'Menu','menu.html',body,'menu-page')

def story_page(r):
    facts=''.join(f'<article><span>0{i}</span><h3>{esc(text)}</h3><p>Production copy, dates, quotes and photography require owner review.</p></article>' for i,text in enumerate(r['facts'],1))
    body=f'<header class="story-hero"><div class="story-art">{art(r["motif"],r["name"])}</div><div><div class="eyebrow">Story direction</div><h1>Build credibility without inventing the restaurant’s history.</h1><p>The final story should use owner-approved milestones, people, archival materials and quotes. This demo only establishes the structure and tone.</p></div></header><section class="story-cards">{facts}</section><aside class="fact-panel"><h2>Still required before launch</h2><p>Founding dates, ownership, chef biographies, recipes, photography rights, awards and all current operating claims.</p></aside>'
    return shell(r,'Story','story.html',body,'story-page')

def tool_page(r):
    opts=''.join(f'<option>{esc(o)}</option>' for o in r['options'])
    body=f'<header class="page-head"><div class="eyebrow">Interactive sales-demo tool</div><h1>{esc(r["toolName"])}</h1><p>{esc(r["toolCopy"])}</p></header><section class="tool-shell" data-tool><div class="tool-controls"><label>Guests<input type="range" min="1" max="50" value="6" name="guests"></label><label>Direction<select name="style">{opts}</select></label><label class="check"><input type="checkbox" name="extra"> Add allergy, accessibility, timing or celebration note</label><button class="btn" type="button" data-build-plan>Build demo plan</button></div><div class="tool-output" data-tool-output><small>Planning summary</small><h2>Choose your options</h2><p>This demonstration does not send an order, reservation or contact request.</p></div></section>'
    return shell(r,r['toolName'],r['tool'],body,'tool-page')

def visit_page(r):
    body=f'<header class="page-head"><div class="eyebrow">Visit planning</div><h1>Give guests the practical details without making them hunt.</h1><p>This page is intentionally honest: address, phone, live hours, parking, reservation links and accessibility details must be confirmed before launch.</p></header><section class="visit-grid"><article><h2>Area</h2><p>{esc(r["area"])}</p><p>Exact address and map link require owner confirmation.</p></article><article><h2>Before you go</h2><p>Confirm current hours, menu availability, reservations, parking and event schedules directly with the restaurant.</p></article><article><h2>Future production links</h2><p>Call • Directions • Order • Reserve • Events • Accessibility</p></article></section><form class="demo-form" data-demo-form><h2>Demo inquiry flow</h2><label>Name<input required></label><label>Email<input type="email" required></label><label>Message<textarea required></textarea></label><button class="btn" type="submit">Preview confirmation</button><p data-form-status></p></form>'
    return shell(r,'Visit','visit.html',body,'visit-page')

def css(r):
    return f''':root{{--bg:{r['bg']};--ink:{r['ink']};--accent:{r['accent']};--paper:#fffdf9;--line:color-mix(in srgb,var(--ink) 18%,transparent);--shadow:0 20px 55px rgba(20,15,12,.12)}}*{{box-sizing:border-box}}html{{scroll-behavior:smooth}}body{{margin:0;background:var(--bg);color:var(--ink);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;line-height:1.6}}a{{color:inherit}}.skip{{position:absolute;left:-999px}}.skip:focus{{left:1rem;top:1rem;background:#fff;padding:.7rem;z-index:20}}.notice{{padding:.55rem 1rem;text-align:center;background:var(--ink);color:var(--bg);font-size:.82rem}}.site-nav{{position:sticky;top:0;z-index:10;display:flex;align-items:center;justify-content:space-between;padding:1rem clamp(1rem,4vw,4rem);background:color-mix(in srgb,var(--bg) 90%,white);backdrop-filter:blur(12px);border-bottom:1px solid var(--line)}}.brand{{font-family:Georgia,serif;font-size:1.25rem;font-weight:800;text-decoration:none}}.nav-links{{display:flex;gap:1rem;align-items:center}}.nav-links a{{text-decoration:none;padding:.35rem .15rem;border-bottom:2px solid transparent}}.nav-links a[aria-current="page"]{{border-color:var(--accent)}}.nav-toggle{{display:none}}main{{max-width:1180px;margin:auto;padding:clamp(2rem,5vw,5rem) clamp(1rem,4vw,3rem)}}h1,h2,h3{{font-family:Georgia,serif;line-height:1.08;margin-top:0}}h1{{font-size:clamp(2.7rem,7vw,6.6rem);max-width:15ch}}h2{{font-size:clamp(1.7rem,3vw,3rem)}}p{{max-width:70ch}}.eyebrow{{text-transform:uppercase;letter-spacing:.12em;font-weight:800;font-size:.76rem;color:var(--accent);margin-bottom:1rem}}.hero{{display:grid;gap:2rem;align-items:center;min-height:64vh}}.hero.split,.hero.editorial{{grid-template-columns:1.1fr .9fr}}.hero.mosaic{{grid-template-columns:1fr .75fr;position:relative}}.hero.marquee{{display:flex;flex-direction:column;align-items:center;text-align:center}}.hero.marquee h1,.hero.marquee p{{max-width:18ch}}.hero.marquee p{{max-width:60ch}}.hero-art{{color:var(--accent);background:var(--paper);border:1px solid var(--line);border-radius:2rem;padding:1.5rem;box-shadow:var(--shadow)}}.hero-art svg,.story-art svg{{width:100%;max-height:430px}}.hero-art.wide{{width:min(700px,100%)}}.hero-note{{position:absolute;right:1rem;bottom:1rem;background:var(--ink);color:var(--bg);padding:.7rem 1rem;border-radius:999px;font-size:.78rem}}.actions{{display:flex;gap:1rem;align-items:center;flex-wrap:wrap}}.btn{{display:inline-flex;border:0;border-radius:999px;background:var(--accent);color:white;padding:.85rem 1.25rem;text-decoration:none;font-weight:800;cursor:pointer}}.text-link{{font-weight:800}}.feature-grid,.menu-preview-grid,.visit-grid,.story-cards{{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;margin:3rem 0}}.feature-card,.menu-preview,.visit-grid article,.story-cards article,.menu-group,.fact-panel,.demo-form,.tool-shell{{background:var(--paper);border:1px solid var(--line);border-radius:1.35rem;padding:1.4rem;box-shadow:0 12px 30px rgba(20,15,12,.07)}}.feature-card span,.story-cards span{{font-weight:900;color:var(--accent)}}.page-head{{padding:3rem 0 1rem;border-bottom:1px solid var(--line)}}.page-head h1{{font-size:clamp(2.6rem,6vw,5rem)}}.menu-search{{display:flex;justify-content:space-between;gap:1rem;align-items:end;margin:2rem 0}}input,select,textarea{{width:100%;padding:.8rem;border-radius:.8rem;border:1px solid var(--line);background:white;color:var(--ink)}}label{{display:grid;gap:.4rem;font-weight:700}}.menu-board{{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem}}.menu-group ul{{list-style:none;padding:0;margin:0}}.menu-group li{{padding:.9rem 0;border-top:1px solid var(--line);font-weight:800}}.menu-group li span{{display:block;font-size:.78rem;font-weight:500;opacity:.68}}.story-hero{{display:grid;grid-template-columns:.8fr 1.2fr;gap:2rem;align-items:center}}.story-art{{color:var(--accent);background:var(--paper);border-radius:2rem;padding:1.5rem}}.fact-panel{{margin-top:1rem}}.tool-shell{{display:grid;grid-template-columns:.9fr 1.1fr;gap:2rem;margin-top:2rem}}.tool-controls{{display:grid;gap:1rem}}.tool-output{{border-radius:1rem;background:var(--ink);color:var(--bg);padding:2rem}}.demo-form{{display:grid;gap:1rem;max-width:720px;margin:2rem auto}}footer{{display:flex;gap:1rem;justify-content:space-between;flex-wrap:wrap;padding:2rem clamp(1rem,4vw,4rem);background:var(--ink);color:var(--bg)}}footer p{{width:100%;margin:0;font-size:.82rem;opacity:.8}}@media(max-width:800px){{.nav-toggle{{display:block}}.nav-links{{display:none;position:absolute;top:100%;left:0;right:0;background:var(--paper);padding:1rem;flex-direction:column;align-items:stretch}}.nav-links.open{{display:flex}}.hero.split,.hero.editorial,.hero.mosaic,.story-hero,.tool-shell{{grid-template-columns:1fr}}.feature-grid,.menu-preview-grid,.visit-grid,.story-cards,.menu-board{{grid-template-columns:1fr}}h1{{font-size:clamp(2.4rem,12vw,4.6rem)}}.hero-note{{position:static;display:inline-block}}}}'''

JS="""const toggle=document.querySelector('[data-nav-toggle]');const links=document.querySelector('[data-nav-links]');if(toggle&&links){toggle.addEventListener('click',()=>{const open=links.classList.toggle('open');toggle.setAttribute('aria-expanded',String(open));});}const search=document.querySelector('[data-menu-search]');const items=[...document.querySelectorAll('[data-menu-item]')];const count=document.querySelector('[data-menu-count]');function filter(){if(!search)return;const q=search.value.toLowerCase();let shown=0;items.forEach(item=>{const ok=item.textContent.toLowerCase().includes(q);item.hidden=!ok;if(ok)shown++;});if(count)count.textContent=`${shown} concept items shown`;}if(search){search.addEventListener('input',filter);filter();}const tool=document.querySelector('[data-tool]');if(tool){const button=tool.querySelector('[data-build-plan]');button?.addEventListener('click',()=>{const guests=tool.querySelector('[name=guests]')?.value||'6';const style=tool.querySelector('[name=style]')?.value||'selected direction';const extra=tool.querySelector('[name=extra]')?.checked;tool.querySelector('[data-tool-output]').innerHTML=`<small>Demo plan</small><h2>${guests} guests • ${style}</h2><p>${extra?'Include the added note and confirm details directly with the restaurant.':'Confirm availability, pricing and operating details directly with the restaurant.'}</p>`;});}const form=document.querySelector('[data-demo-form]');if(form){form.addEventListener('submit',event=>{event.preventDefault();form.querySelector('[data-form-status]').textContent='Demo only — no message was sent.';});}"""

for r in restaurants:
    folder=ROOT/r['slug']
    if folder.exists(): shutil.rmtree(folder)
    folder.mkdir(parents=True)
    files={
      'index.html':home_page(r),
      'menu.html':menu_page(r),
      'story.html':story_page(r),
      r['tool']:tool_page(r),
      'visit.html':visit_page(r),
      'site.css':css(r),
      'site.js':JS,
      'EVIDENCE.md':f"# {r['name']} evidence\n\n- 5/5 required pages created\n- Restaurant-specific conversion page: {r['toolName']}\n- Structural, internal-link and JavaScript validation: completed\n- Browser-rendered visual QA: pending\n- Premium status: not claimed\n"
    }
    for name,content in files.items(): (folder/name).write_text(content,encoding='utf-8')

# Update status report.
status_path=ROOT/'RESTAURANT-DEMO-STATUS.md'
status=status_path.read_text(encoding='utf-8') if status_path.exists() else '# Restaurant Demo Status\n'
block='<!-- BLOCK 8 START -->\n\n## Block 8 — full five-page demos; static QA completed; browser visual QA pending\n\n'+'\n'.join(f"- {r['name']} — 5/5 pages; structural, internal-link and JavaScript validation completed; browser visual QA pending; premium not claimed" for r in restaurants)+'\n\n<!-- BLOCK 8 END -->\n\n'
status=re.sub(r'<!-- BLOCK 8 START -->.*?<!-- BLOCK 8 END -->\n*','',status,flags=re.S)
insert_at=status.find('\n',status.find('# '))+1 if status.startswith('# ') else 0
status=status[:insert_at]+'\n'+block+status[insert_at:]
status_path.write_text(status,encoding='utf-8')

# Update portfolio entries.
index_path=ROOT/'index.html'
index=index_path.read_text(encoding='utf-8')
entries=[]
for r in restaurants:
    entries.append(json.dumps({'name':r['name'],'area':r['area'],'cuisine':r['cuisine'],'href':r['slug']+'/index.html','emoji':'🍽','status':'static','description':'Five-page restaurant-specific sales demo; static QA complete, browser visual QA pending.'},ensure_ascii=False,separators=(',',':')))
for r in restaurants:
    pattern=re.compile(r'\{"name":"'+re.escape(r['name'])+r'".*?\},?')
    index=pattern.sub('',index)
index=index.replace('const concepts=[','const concepts=['+','.join(entries)+',',1)
index=index.replace('[,','[').replace(',,',',')
index_path.write_text(index,encoding='utf-8')

# Validation.
errors=[]
for r in restaurants:
    folder=ROOT/r['slug']
    required=REQUIRED+[r['tool']]
    for name in required:
        p=folder/name
        if not p.exists(): errors.append(f'missing {p}')
        else:
            text=p.read_text(encoding='utf-8')
            if 'Unofficial sales demonstration' not in text: errors.append(f'missing disclosure {p}')
            for href in re.findall(r'href="([^"]+\.html)"',text):
                if not (folder/href).exists(): errors.append(f'broken link {p}: {href}')
    result=subprocess.run(['node','--check',str(folder/'site.js')],capture_output=True,text=True)
    if result.returncode: errors.append(f'javascript {folder}: {result.stderr}')
    if r['slug']+'/index.html' not in index_path.read_text(encoding='utf-8'): errors.append(f'portfolio missing {r["slug"]}')
    if r['name'] not in status_path.read_text(encoding='utf-8'): errors.append(f'status missing {r["name"]}')
if errors:
    raise SystemExit('\n'.join(errors))
print(f'Validated {len(restaurants)} restaurants and {len(restaurants)*5} HTML pages.')
